import{_ as t,o as a,c as s,ag as o}from"./chunks/framework.BYehg5q7.js";const g=JSON.parse('{"title":"Agent Access","description":"","frontmatter":{},"headers":[],"relativePath":"guide/agent-access.md","filePath":"guide/agent-access.md","lastUpdated":1774954986000}'),n={name:"guide/agent-access.md"};function i(r,e,l,h,c,p){return a(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="agent-access" tabindex="-1">Agent Access <a class="header-anchor" href="#agent-access" aria-label="Permalink to &quot;Agent Access&quot;">​</a></h1><p>Agent Access is an opt-in feature that lets AI agents query your lab data — coding agents (Claude Code, Cursor), messenger bots (Hermes Agent, OpenClaw), or any MCP-compatible tool. The agent pulls your latest lab context from getbased to answer questions like &quot;how&#39;s my iron trending?&quot; or &quot;what changed since my last draw?&quot;</p><p>Only a read-only text summary is shared. Your raw data and sync mnemonic never leave your browser.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>getbased (browser)  ──saves context──▶  Context Gateway  ◀──queries with token──  AI agent (Claude Code, Hermes, etc.)</span></span></code></pre></div><ol><li>You enable <strong>Agent Access</strong> in getbased and receive a read-only token</li><li>getbased pushes a pre-built text summary of your labs, context cards, supplements, goals, and notes to the context gateway</li><li>Your AI agent uses the token to read that summary and answer questions</li></ol><p>The gateway stores only the same assembled text context that the in-app AI chat uses — no raw data, no database access, no mnemonic. The summary is refreshed automatically whenever you save changes in getbased.</p><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><h3 id="_1-enable-agent-access" tabindex="-1">1. Enable Agent Access <a class="header-anchor" href="#_1-enable-agent-access" aria-label="Permalink to &quot;1. Enable Agent Access&quot;">​</a></h3><ol><li>Open <strong>Settings → Data → Agent Access</strong></li><li>Toggle it <strong>on</strong></li><li>A read-only token is generated and displayed</li></ol><p>Copy the token — you will paste it into your agent&#39;s configuration.</p><h3 id="_2-connect-your-agent" tabindex="-1">2. Connect your agent <a class="header-anchor" href="#_2-connect-your-agent" aria-label="Permalink to &quot;2. Connect your agent&quot;">​</a></h3><p>Paste the token into whichever tool you use to run your AI agent. See <a href="#compatible-tools">Compatible Tools</a> below for specific instructions.</p><h3 id="_3-query" tabindex="-1">3. Query <a class="header-anchor" href="#_3-query" aria-label="Permalink to &quot;3. Query&quot;">​</a></h3><p>Ask your agent anything about your labs. It reads your latest context from the gateway and responds.</p><div class="tip custom-block"><p class="custom-block-title">Token visibility</p><p>The token is masked by default in Settings. Click <strong>Show</strong> to reveal it, or <strong>Copy</strong> to put it on your clipboard. The clipboard is cleared after 60 seconds.</p></div><h2 id="multi-profile-support" tabindex="-1">Multi-Profile Support <a class="header-anchor" href="#multi-profile-support" aria-label="Permalink to &quot;Multi-Profile Support&quot;">​</a></h2><p>If you track labs for multiple people (yourself, a partner, a parent), each profile&#39;s context is stored separately on the gateway. Bots can query by profile ID to pull the right person&#39;s data.</p><ul><li>When you save context, getbased pushes each profile&#39;s summary under its own ID</li><li>The bot&#39;s <code>getbased_list_profiles</code> tool returns all available profiles with their names</li><li>The bot&#39;s <code>getbased_lab_context</code> tool accepts an optional profile ID parameter — if omitted, it returns the active profile</li></ul><p>Switch to the profile you want to update in getbased, make your changes, and the gateway receives that profile&#39;s latest context automatically.</p><h2 id="compatible-tools" tabindex="-1">Compatible Tools <a class="header-anchor" href="#compatible-tools" aria-label="Permalink to &quot;Compatible Tools&quot;">​</a></h2><p>Agent Access works with any agent that can call the context gateway&#39;s API using your token. The universal adapter is <a href="https://github.com/elkimek/getbased-mcp" target="_blank" rel="noreferrer">getbased-mcp</a> — an MCP server that exposes your lab context as tools.</p><h3 id="getbased-mcp" tabindex="-1">getbased-mcp <a class="header-anchor" href="#getbased-mcp" aria-label="Permalink to &quot;getbased-mcp&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/elkimek/getbased-mcp.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> getbased-mcp</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span></code></pre></div><p>Add it to your agent&#39;s MCP config with your token and gateway URL. Works with any MCP-compatible agent — Claude Code, Cursor, Windsurf, <a href="https://github.com/hermes-agent/hermes-agent" target="_blank" rel="noreferrer">Hermes Agent</a>, <a href="https://openclaw.ai" target="_blank" rel="noreferrer">OpenClaw</a>, and more.</p><h3 id="hermes-agent-example" tabindex="-1">Hermes Agent example <a class="header-anchor" href="#hermes-agent-example" aria-label="Permalink to &quot;Hermes Agent example&quot;">​</a></h3><p><a href="https://github.com/hermes-agent/hermes-agent" target="_blank" rel="noreferrer">Hermes Agent</a> is a self-hosted AI assistant with built-in support for Matrix, Telegram, Signal, Discord, and other messengers. Configure getbased-mcp in <code>~/.hermes/config.yaml</code>:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">mcp_servers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  getbased</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    command</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">python3</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    args</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/path/to/getbased_mcp.py</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    env</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      GETBASED_GATEWAY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">https://sync.getbased.health</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      GETBASED_TOKEN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">your-token</span></span></code></pre></div><p>Then restart the gateway: <code>hermes gateway restart</code></p><p>getbased-mcp provides these tools:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Description</th></tr></thead><tbody><tr><td><code>getbased_lab_context</code></td><td>Full lab summary — values, ranges, trends, context cards, supplements, goals</td></tr><tr><td><code>getbased_section</code></td><td>Query a specific section (hormones, biometrics, etc.) or list available sections</td></tr><tr><td><code>getbased_list_profiles</code></td><td>List all profiles by name and ID</td></tr></tbody></table><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><p>Agent Access is designed to share the minimum needed for a bot to be useful:</p><ul><li><strong>Read-only token</strong> — the token grants access to a pre-built text summary only. No writes, no database queries, no mutations</li><li><strong>No raw data exposed</strong> — the gateway stores the same assembled context the in-app AI chat uses, not your underlying lab entries or personal records</li><li><strong>Mnemonic never leaves your browser</strong> — the sync mnemonic is a separate system. Agent Access does not use or transmit it</li><li><strong>Revocable at any time</strong> — toggle Agent Access off in Settings to immediately invalidate the token. You can also click <strong>Regenerate</strong> to create a new token, which invalidates the old one</li><li><strong>Self-hostable</strong> — the context gateway runs on the same server as the <a href="./cross-device-sync.html#running-your-own-relay">sync relay</a>. Self-host both for full control over where your summary is stored</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Your token grants access to your lab summary. Treat it like a password — do not share it publicly or commit it to a public repository.</p></div><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="bot-sees-the-wrong-profile" tabindex="-1">Bot sees the wrong profile <a class="header-anchor" href="#bot-sees-the-wrong-profile" aria-label="Permalink to &quot;Bot sees the wrong profile&quot;">​</a></h3><p>The gateway serves whichever profiles have been pushed. If the bot returns data for the wrong person:</p><ol><li>Open getbased and switch to the correct profile</li><li>Make any edit and save (or toggle Agent Access off and back on) to force a fresh push</li><li>Ask the bot again — use the profile ID parameter if you have multiple profiles</li></ol><h3 id="bot-returns-stale-data" tabindex="-1">Bot returns stale data <a class="header-anchor" href="#bot-returns-stale-data" aria-label="Permalink to &quot;Bot returns stale data&quot;">​</a></h3><p>The gateway is updated whenever you save changes in getbased. If the bot&#39;s answers seem outdated:</p><ol><li>Confirm <strong>Agent Access</strong> is still toggled on in <strong>Settings → Data</strong></li><li>Open getbased in your browser — the push happens from the browser, so it needs to be open at least once after your latest changes</li><li>Check your network connection — the push requires internet access to reach the gateway</li></ol><h3 id="token-not-working" tabindex="-1">Token not working <a class="header-anchor" href="#token-not-working" aria-label="Permalink to &quot;Token not working&quot;">​</a></h3><ul><li>Make sure you copied the full token (no trailing spaces)</li><li>Check that Agent Access is still enabled — disabling it invalidates the token</li><li>If you clicked <strong>Regenerate</strong>, update your bot config with the new token — the old one no longer works</li></ul><h3 id="bot-cannot-reach-the-gateway" tabindex="-1">Bot cannot reach the gateway <a class="header-anchor" href="#bot-cannot-reach-the-gateway" aria-label="Permalink to &quot;Bot cannot reach the gateway&quot;">​</a></h3><p>If you self-host the gateway, verify that:</p><ul><li>The gateway server is running and accessible from the bot&#39;s network</li><li>Your bot config points to the correct gateway URL (e.g., <code>https://sync.yourdomain.com</code>)</li><li>TLS is configured correctly — the bot needs HTTPS access</li></ul>`,47)])])}const u=t(n,[["render",i]]);export{g as __pageData,u as default};
